import React, { useEffect, useState } from "react";
import { Pie } from "react-chartjs-2";
import { Chart as ChartJS, ArcElement, Tooltip, Legend } from 'chart.js';

ChartJS.register(ArcElement, Tooltip, Legend);

const Dashboard = () => {
  const [cumulativeData, setCumulativeData] = useState({});

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("journalEntries")) || [];

    const totals = {};

    stored.forEach(entry => {
      if (entry.analyzed && entry.analysis) {
        let analysis;

        // Parse string to object if needed
        if (typeof entry.analysis === "string") {
          analysis = parseAnalysisString(entry.analysis);
        } else {
          analysis = entry.analysis;
        }

        for (const key in analysis) {
          const value = parseFloat(analysis[key]);
          totals[key] = (totals[key] || 0) + value;
        }
      }
    });

    setCumulativeData(totals);
  }, []);

  const parseAnalysisString = (str) => {
    const result = {};
    const parts = str.split(",");
    parts.forEach((part) => {
      const [emotion, percent] = part.trim().split(":");
      result[emotion.toLowerCase()] = parseFloat(percent.replace("%", "").trim());
    });
    return result;
  };

  const labels = Object.keys(cumulativeData);
  const dataValues = Object.values(cumulativeData);

  const data = {
    labels,
    datasets: [
      {
        label: "Cumulative Emotion Analysis",
        data: dataValues,
        backgroundColor: [
          "#7e5f40",
          "#d6b98c",
          "#7b8b58",
          "#8c6fc3",
          "#f5e6c8",
          "#5a4432",
          "#fdfaf5",
          "#7a6651"
        ],
        borderColor: "#fff",
        borderWidth: 1
      }
    ]
  };

  return (
    <div className="dashboard-page">
      <h1>Cumulative Emotion Analysis</h1>
      {labels.length > 0 ? (
        <div className="chart-container">
          <Pie data={data} />
        </div>
      ) : (
        <p>No analyzed journal data found.</p>
      )}

      <style>{`
        .dashboard-page {
          font-family: 'Cedarville Cursive', cursive;
          padding: 2rem;
          background-color: var(--bg-parchment);
          color: var(--text);
          display: flex;
          flex-direction: column;
          align-items: center;
        }

        .chart-container {
          max-width: 500px;
          width: 100%;
        }

        h1 {
          color: var(--font-text);
          font-size: 2rem;
          margin-bottom: 1.5rem;
        }
      `}</style>
    </div>
  );
};

export default Dashboard;
